class Solution {
public:
    string countOfAtoms(string formula) {
        int n = formula.size();
        stack<unordered_map<string, int>> stk;
        stk.push({});

        int i = 0;
        while (i < n) {
            if (formula[i] == '(') {
                stk.push({});
                i++;
            } else if (formula[i] == ')') {
                auto top = stk.top();
                stk.pop();
                int num = 0, j = i + 1;
                while (j < n && isdigit(formula[j])) {
                    num = num * 10 + (formula[j] - '0');
                    j++;
                }
                if (num == 0) num = 1;
                for (auto& [k, v] : top) {
                    stk.top()[k] += v * num;
                }
                i = j;
            } else {
                int j = i + 1;
                while (j < n && islower(formula[j])) j++;
                string name = formula.substr(i, j - i);
                int num = 0;
                while (j < n && isdigit(formula[j])) {
                    num = num * 10 + (formula[j] - '0');
                    j++;
                }
                if (num == 0) num = 1;
                stk.top()[name] += num;
                i = j;
            }
        }

        auto& cnt = stk.top();
        vector<pair<string, int>> vec(cnt.begin(), cnt.end());
        sort(vec.begin(), vec.end());

        string res;
        for (auto& [k, v] : vec) {
            res += k;
            if (v > 1) res += to_string(v);
        }
        return res;
    }
};
